import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

function MarkAttendance({ user }) {
  const [attendanceData, setAttendanceData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [markedTime, setMarkedTime] = useState(null);
  const navigate = useNavigate();

  // Function to get current Indian time
  const getIndianTime = () => {
    return new Date().toLocaleString('en-IN', {
      timeZone: 'Asia/Kolkata',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: true
    });
  };

  // Function to get Indian date
  const getIndianDate = () => {
    return new Date().toLocaleDateString('en-IN', {
      timeZone: 'Asia/Kolkata',
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  useEffect(() => {
    const checkAttendance = async () => {
      try {
        const response = await api.get('/attendance/');
        setAttendanceData(response.data);
        
        // If attendance is already marked, you might want to fetch the marked time
        // This would require a backend change to return the created_at time
        if (response.data.already_marked) {
          // You could fetch the attendance record to get the exact time
          // For now, we'll use current time as placeholder
          setMarkedTime(getIndianTime());
        }
      } catch (err) {
        setError('Failed to load attendance data');
      } finally {
        setLoading(false);
      }
    };   
    checkAttendance();
  }, []);

  const handleMarkAttendance = async () => {
    setSubmitting(true);
    setError('');
    
    try {
      const response = await api.post('/attendance/');
      setMarkedTime(getIndianTime());
      
      // Update attendanceData to reflect that attendance is marked
      setAttendanceData({
        ...attendanceData,
        already_marked: true,
        can_mark: false
      });
      
      // Optional: Show success message before redirect
      setTimeout(() => {
        if (user.is_admin) {
          navigate('/admin');
        } else {
          navigate('/dashboard');
        }
      }, 1500);
      
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to mark attendance');
    } finally {
      setSubmitting(false);
    }
  };

  const handleBack = () => {
    if (user.is_admin) {
      navigate('/admin');
    } else {
      navigate('/dashboard');
    }
  };

  const getStatusMessage = () => {
    if (attendanceData?.on_leave) {
      return "You are on Leave today";
    }
    if (attendanceData?.on_wfh) {
      return "You are on Work From Home today";
    }
    if (attendanceData?.already_marked) {
      return "You have already marked attendance today";
    }
    return null;
  };

  if (loading) {
    return <div style={styles.loading}>Loading...</div>;
  }

  if (error && !attendanceData?.can_mark) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <h2 style={styles.title}>Mark Attendance</h2>
          <div style={styles.dateTimeContainer}>
            <p style={styles.date}>{getIndianDate()}</p>
            <p style={styles.time}>Current Time: {getIndianTime()}</p>
          </div>
          
          <div style={styles.error}>{error}</div>
          
          <button onClick={handleBack} style={styles.backButton}>Back</button>
        </div>
      </div>
    );
  }

  const statusMessage = getStatusMessage();

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Mark Attendance</h2>
        
        <div style={styles.dateTimeContainer}>
          <p style={styles.date}>{getIndianDate()}</p>
          <p style={styles.time}>Current Time: {getIndianTime()}</p>
          {markedTime && (
            <p style={styles.markedTime}>
              ✓ Attendance marked at: {markedTime}
            </p>
          )}
        </div>
        
        {attendanceData?.can_mark ? (
          <button 
            onClick={handleMarkAttendance} 
            disabled={submitting}
            style={submitting ? styles.disabledButton : styles.markButton}
          >
            {submitting ? 'Marking...' : 'Mark Present'}
          </button>
        ) : (
          <div style={styles.info}>
            <p style={styles.infoText}>{statusMessage}</p>
            {attendanceData?.already_marked && !markedTime && (
              <p style={styles.markedTimePlaceholder}>
                Time will be recorded when you mark attendance
              </p>
            )}
          </div>
        )}
        
        <button onClick={handleBack} style={styles.backButton}>Back to Dashboard</button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '100vh',
    padding: '20px',
    backgroundColor: '#f5f5f5',
  },
  card: {
    background: 'white',
    padding: '40px',
    borderRadius: '16px',
    width: '400px',
    textAlign: 'center',
    boxShadow: '0 5px 15px rgba(0,0,0,0.2)',
    border: '2px solid var(--moss-green)',
  },
  title: {
    color: 'var(--moss-dark)',
    fontSize: '28px',
    marginTop: 0,
    marginBottom: '20px',
    fontWeight: 500,
  },
  dateTimeContainer: {
    backgroundColor: 'var(--moss-pale)',
    padding: '15px',
    borderRadius: '8px',
    marginBottom: '25px',
    border: '1px solid var(--moss-green)',
  },
  date: {
    fontSize: '18px',
    color: 'var(--moss-dark)',
    margin: '0 0 5px 0',
    fontWeight: 500,
  },
  time: {
    fontSize: '16px',
    color: 'var(--moss-green)',
    margin: '5px 0',
  },
  markedTime: {
    fontSize: '16px',
    color: '#2d6a4f',
    margin: '10px 0 0 0',
    padding: '8px',
    backgroundColor: '#e8f5e9',
    borderRadius: '6px',
    border: '1px solid #a5d6a7',
    fontWeight: 500,
  },
  markedTimePlaceholder: {
    fontSize: '14px',
    color: '#666',
    margin: '10px 0 0 0',
    fontStyle: 'italic',
  },
  markButton: {
    padding: '12px 25px',
    backgroundColor: 'var(--moss-green)',
    color: 'white',
    border: '1px solid var(--moss-dark)',
    borderRadius: '8px',
    cursor: 'pointer',
    margin: '10px 5px',
    fontSize: '16px',
    fontFamily: 'Times New Roman, Times, serif',
    transition: '0.2s',
    width: '100%',
    '&:hover': {
      backgroundColor: 'var(--moss-dark)',
    },
  },
  disabledButton: {
    padding: '12px 25px',
    backgroundColor: '#cccccc',
    color: '#666666',
    border: '1px solid #999999',
    borderRadius: '8px',
    cursor: 'not-allowed',
    margin: '10px 5px',
    fontSize: '16px',
    fontFamily: 'Times New Roman, Times, serif',
    width: '100%',
  },
  backButton: {
    padding: '12px 25px',
    backgroundColor: 'var(--moss-pale)',
    color: 'var(--moss-dark)',
    border: '1px solid var(--moss-green)',
    borderRadius: '8px',
    cursor: 'pointer',
    margin: '10px 5px',
    fontSize: '16px',
    fontFamily: 'Times New Roman, Times, serif',
    transition: '0.2s',
    width: '100%',
    '&:hover': {
      backgroundColor: '#d4c8b0',
    },
  },
  error: {
    color: '#a94442',
    backgroundColor: '#f2dede',
    padding: '12px',
    borderRadius: '8px',
    marginBottom: '20px',
    border: '1px solid #ebccd1',
  },
  info: {
    marginBottom: '20px',
  },
  infoText: {
    color: 'var(--moss-dark)',
    backgroundColor: 'var(--moss-pale)',
    padding: '12px',
    borderRadius: '8px',
    fontSize: '16px',
    margin: '0',
  },
  loading: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    height: '100vh',
    fontSize: '20px',
    color: 'var(--moss-dark)',
    backgroundColor: '#f5f5f5',
  },
};

export default MarkAttendance;
